"use client"

import { Swiper, SwiperSlide } from "swiper/react"
import { Pagination, Autoplay, Navigation } from "swiper/modules"

import "swiper/css"
import "swiper/css/pagination"

import Image from "next/image"

const slides = [
    {
        title: "Mở bán khóa JavaScript Pro 👑",
        desc: "Từ 08/08/2024 khóa học sẽ có giá 1.399k. Khi khóa học hoàn thiện sẽ trở về giá gốc.",
        img: "/images/images1.jpg",
    },
    {
        title: "Học Fullstack từ cơ bản",
        desc: "Lộ trình rõ ràng từ HTML → React → Backend.",
        img: "/images/image2.jpg",
    },
]

export default function Home() {
    return (
        <div>
            {/* Slide Show */}
            <div className="relative">

                <Swiper
                    modules={[Pagination, Autoplay, Navigation]}
                    autoplay={{ delay: 4000 }}
                    pagination={{ clickable: true }}
                    navigation
                    loop
                    className="rounded-2xl overflow-hidden"
                >
                    {slides.map((s, i) => (
                        <SwiperSlide key={i}>
                            <div className="flex items-center justify-between bg-gradient-to-r from-purple-600 to-fuchsia-500 text-white p-8 md:p-12">

                                {/* TEXT */}
                                <div className="max-w-xl space-y-4">
                                    <h2 className="text-xl md:text-3xl font-bold">
                                        {s.title}
                                    </h2>

                                    <p className="text-sm md:text-base opacity-90">
                                        {s.desc}
                                    </p>

                                    <button className="mt-2 px-5 py-2 border border-white rounded-full text-sm hover:bg-white hover:text-purple-600 transition">
                                        Học thử miễn phí
                                    </button>
                                </div>

                                {/* IMAGE (ẩn mobile) */}
                                <div className="hidden md:block">
                                    <Image
                                        src={s.img}
                                        alt="slide"
                                        width={260}
                                        height={260}
                                    />
                                </div>

                            </div>
                        </SwiperSlide>
                    ))}
                </Swiper>

            </div>
        </div>
    )
}